function buildQuestions(raw, subjectId, prefix) {
  return raw.map((r, i) => {
    const [type, chapterId, level, stem, options, correct, explanation, reference] = r;
    return {
      id: `${prefix}${i + 1}`,
      type,
      subjectId,
      chapterId,
      chapterLabel: CH[chapterId],
      level,
      stem,
      options: options.map((t, idx) => ({ id: `${prefix}${i}-${idx}`, text: t, correct: correct.includes(idx) })),
      explanation,
      reference,
    };
  });
}
