/* ---------------- Apprendre : résumé de leçon avant l'entraînement ---------------- */
function buildLessonSections(subjectId, chapterId) {
  const chapterIds = chapterId === "all"
    ? CHAPTERS.filter((c) => c.subjectId === subjectId).map((c) => c.id)
    : [chapterId];

  return chapterIds
    .map((chId) => {
      const chapterLabel = CH[chId];
      const facts = [];
      const seen = new Set();
      const pushFact = (explanation, reference) => {
        const key = explanation.trim();
        if (seen.has(key)) return;
        seen.add(key);
        facts.push({ explanation, reference });
      };
      QUESTIONS.filter((q) => q.subjectId === subjectId && q.chapterId === chId)
        .forEach((q) => pushFact(q.explanation, q.reference));
      CASES.filter((c) => c.subjectId === subjectId && c.chapterId === chId)
        .forEach((c) => c.questions.forEach((q) => pushFact(q.explanation, q.reference)));
      return { chapterId: chId, chapterLabel, facts };
    })
    .filter((s) => s.facts.length > 0);
}

