/* ---------------- Diagnostic infirmier — session ---------------- */
function DiagnosticInfirmierScreen({ levelId, onFinish }) {
  const challenges = useMemo(() => {
    const lvl = LEVELS.find((l) => l.id === levelId);
    return shuffle(CLINICAL_CHALLENGES.filter((c) => c.level <= lvl.maxLevel));
  }, [levelId]);

  const [cursor, setCursor] = useState(0);
  const [answer, setAnswer] = useState("");
  const [result, setResult] = useState(null); // null | { verdict, explication, rappel, error }
  const [grading, setGrading] = useState(false);
  const [tally, setTally] = useState({ correct: 0, partiel: 0, incorrect: 0 });

  const current = challenges[cursor];
  const isLast = cursor === challenges.length - 1;

  if (!current) {
    return (
      <div style={{ minHeight: "100vh", background: COLORS.bg, display: "flex", alignItems: "center", justifyContent: "center", padding: 20, fontFamily: "'IBM Plex Sans', sans-serif" }}>
        <div style={{ maxWidth: 420, background: COLORS.surface, border: `1px solid ${COLORS.line}`, borderRadius: 16, padding: 28, textAlign: "center" }}>
          <div style={{ fontSize: 13, color: COLORS.ink, marginBottom: 16 }}>Aucun défi disponible pour ce niveau.</div>
          <button onClick={onFinish} style={{ ...primaryBtn, width: "100%" }}>Retour au tableau de bord</button>
        </div>
      </div>
    );
  }

  const submit = async () => {
    if (!answer.trim() || grading) return;
    setGrading(true);
    const res = await gradeClinicalAnswer(current, answer.trim());
    setGrading(false);
    setResult(res);
    if (!res.error) setTally((t) => ({ ...t, [res.verdict]: t[res.verdict] + 1 }));
  };

  const next = () => {
    setAnswer("");
    setResult(null);
    if (isLast) { onFinish(tally); return; }
    setCursor((c) => c + 1);
  };

  const verdictStyle = {
    correct: { tone: "green", label: "✓ Correct" },
    partiel: { tone: "amber", label: "◐ Partiellement correct" },
    incorrect: { tone: "red", label: "✕ Incorrect" },
  };

  return (
    <div style={{ minHeight: "100vh", background: COLORS.bg, fontFamily: "'IBM Plex Sans', sans-serif" }}>
      <div style={{ background: COLORS.surface, borderBottom: `1px solid ${COLORS.line}`, padding: "10px 18px" }}>
        <div style={{ maxWidth: 680, margin: "0 auto", display: "flex", justifyContent: "space-between", alignItems: "center", fontSize: 12.5, color: COLORS.inkSoft }}>
          <span>Diagnostic infirmier · Défi <b style={{ color: COLORS.ink }}>{cursor + 1}</b> / {challenges.length}</span>
          <span style={{ fontFamily: "'IBM Plex Mono', monospace", color: COLORS.green, fontWeight: 600 }}>
            {tally.correct} correct(s) · {tally.partiel} partiel(s)
          </span>
        </div>
        <div style={{ maxWidth: 680, margin: "8px auto 0", height: 4, background: COLORS.line, borderRadius: 999 }}>
          <div style={{ width: `${((cursor + 1) / challenges.length) * 100}%`, height: 4, background: COLORS.blue, borderRadius: 999, transition: "width .25s" }} />
        </div>
      </div>

      <div style={{ maxWidth: 680, margin: "0 auto", padding: "24px 18px 80px" }}>
        <Badge tone="blue">{DIAGNOSTIC_TYPES.find((t) => t.id === current.type)?.label}</Badge>

        <div style={{ background: COLORS.surface, border: `1px solid ${COLORS.line}`, borderRadius: 14, padding: 20, marginTop: 14, marginBottom: 16 }}>
          <div style={{ fontSize: 14.5, color: COLORS.ink, lineHeight: 1.7, whiteSpace: "pre-wrap" }}>{current.stem}</div>
        </div>

        <textarea
          value={answer}
          onChange={(e) => setAnswer(e.target.value)}
          disabled={!!result}
          rows={4}
          placeholder="Votre réponse…"
          style={{ ...inputStyle, fontFamily: "'IBM Plex Sans', sans-serif", resize: "vertical", opacity: result ? 0.7 : 1 }}
        />

        {result && !result.error && (
          <div style={{ background: COLORS.surface, border: `1px solid ${COLORS.line}`, borderRadius: 12, padding: 16, marginTop: 14 }}>
            <Badge tone={verdictStyle[result.verdict].tone}>{verdictStyle[result.verdict].label}</Badge>
            <div style={{ fontSize: 13, color: COLORS.ink, lineHeight: 1.6, marginTop: 10 }}>{result.explication}</div>
            {result.verdict !== "correct" && (
              <div style={{ marginTop: 10, paddingTop: 10, borderTop: `1px dashed ${COLORS.line}` }}>
                <div style={{ fontSize: 10.5, fontWeight: 700, color: COLORS.blueDeep, letterSpacing: 0.4, marginBottom: 4 }}>RAPPEL DU COURS</div>
                <div style={{ fontSize: 13, color: COLORS.ink, lineHeight: 1.6 }}>{result.rappel}</div>
              </div>
            )}
          </div>
        )}

        {result && result.error && (
          <div style={{ background: COLORS.redSoft, border: `1px solid ${COLORS.line}`, borderRadius: 12, padding: 14, marginTop: 14, fontSize: 12.5, color: COLORS.red }}>
            La correction IA n'a pas pu être obtenue (connexion ou service indisponible). Réessayez.
          </div>
        )}

        <div style={{ display: "flex", justifyContent: "flex-end", marginTop: 16 }}>
          {!result || result.error ? (
            <button onClick={submit} disabled={!answer.trim() || grading} style={{ ...primaryBtn, opacity: !answer.trim() || grading ? 0.5 : 1 }}>
              {grading ? "Correction en cours…" : "Valider ma réponse"}
            </button>
          ) : (
            <button onClick={next} style={{ ...primaryBtn, background: COLORS.green }}>
              {isLast ? "Terminer" : "Défi suivant →"}
            </button>
          )}
        </div>

        <button onClick={() => onFinish(tally)} style={{ ...secondaryBtn, marginTop: 22, fontSize: 12, color: COLORS.inkSoft }}>
          Quitter
        </button>
      </div>
    </div>
  );
}

/* ---------------- Patient virtuel — choix du cas ---------------- */
function VirtualPatientSetupScreen({ onBack, onLaunch }) {
  return (
    <div style={{ minHeight: "100vh", background: COLORS.bg, fontFamily: "'IBM Plex Sans', sans-serif" }}>
      <TopBar onLogout={onBack} />
      <div style={{ maxWidth: 720, margin: "0 auto", padding: "30px 18px 60px" }}>
        <button onClick={onBack} style={{ ...secondaryBtn, marginBottom: 18, padding: "6px 12px", fontSize: 12.5 }}>← Retour</button>
        <h1 style={{ fontFamily: "'Space Grotesk', sans-serif", fontSize: 20, color: COLORS.ink, marginBottom: 4 }}>Patient virtuel</h1>
        <p style={{ color: COLORS.inkSoft, fontSize: 13, marginBottom: 6 }}>
          Discutez avec un patient simulé, demandez les examens utiles, puis posez votre diagnostic, la conduite à tenir et les soins infirmiers.
        </p>
        <div style={{ background: COLORS.amberSoft, border: `1px solid ${COLORS.line}`, borderRadius: 10, padding: "9px 13px", fontSize: 11.5, color: COLORS.amber, marginBottom: 20 }}>
          Cas scriptés à l'avance (faits et résultats d'examens fixes) : l'IA ne fait que jouer le ton du patient, elle n'invente jamais de fait médical.
        </div>

        <div style={{ display: "flex", flexDirection: "column", gap: 10 }}>
          {VIRTUAL_PATIENT_CASES.map((c) => (
            <button
              key={c.id}
              onClick={() => onLaunch(c.id)}
              style={{
                textAlign: "left", borderRadius: 12, padding: 16, cursor: "pointer",
                border: `1px solid ${COLORS.line}`, background: COLORS.surface,
                display: "flex", justifyContent: "space-between", alignItems: "center", gap: 10,
              }}
            >
              <div>
                <div style={{ fontFamily: "'Space Grotesk', sans-serif", fontWeight: 600, fontSize: 14, color: COLORS.ink }}>{c.profil}</div>
                <div style={{ fontSize: 12, color: COLORS.inkSoft, marginTop: 3 }}>{c.motif}</div>
              </div>
              <Badge tone="blue">{LEVELS[c.level - 1]?.label || `Niveau ${c.level}`}</Badge>
            </button>
          ))}
        </div>
      </div>
    </div>
  );
}

/* ---------------- Patient virtuel — session ---------------- */
function VirtualPatientScreen({ caseId, onFinish }) {
  const caseData = useMemo(() => VIRTUAL_PATIENT_CASES.find((c) => c.id === caseId), [caseId]);
  const [messages, setMessages] = useState(() => [{ role: "patient", text: caseData.ouverture }]);
  const [input, setInput] = useState("");
  const [asking, setAsking] = useState(false);
  const [examResults, setExamResults] = useState([]);
  const [showExamMenu, setShowExamMenu] = useState(false);
  const [phase, setPhase] = useState("chat"); // "chat" | "answer" | "result"
  const [finalAnswer, setFinalAnswer] = useState("");
  const [grading, setGrading] = useState(false);
  const [result, setResult] = useState(null);
  const scrollRef = useRef(null);

  useEffect(() => {
    if (scrollRef.current) scrollRef.current.scrollTop = scrollRef.current.scrollHeight;
  }, [messages, phase]);

  const askQuestion = async () => {
    if (!input.trim() || asking) return;
    const question = input.trim();
    setMessages((prev) => [...prev, { role: "etudiant", text: question }]);
    setInput("");
    setAsking(true);
    const reponse = await askVirtualPatient(caseData, question);
    setAsking(false);
    setMessages((prev) => [...prev, { role: "patient", text: reponse || "Le patient ne répond pas pour l'instant (problème de connexion)." }]);
  };

  const requestExam = (exam) => {
    setShowExamMenu(false);
    if (examResults.some((e) => e.nom === exam.nom)) return;
    setExamResults((prev) => [...prev, exam]);
    setMessages((prev) => [
      ...prev,
      { role: "etudiant", text: `Je demande : ${exam.nom}` },
      { role: "examen", text: `${exam.nom} → ${exam.resultat}` },
    ]);
  };

  const submitFinal = async () => {
    if (!finalAnswer.trim() || grading) return;
    setGrading(true);
    const res = await gradeClinicalAnswer(
      { stem: `${caseData.motif} (${caseData.profil}). Diagnostic, conduite à tenir et soins infirmiers attendus.`, expected: caseData.expected },
      finalAnswer.trim()
    );
    setGrading(false);
    setResult(res);
    setPhase("result");
  };

  const verdictStyle = {
    correct: { tone: "green", label: "✓ Correct" },
    partiel: { tone: "amber", label: "◐ Partiellement correct" },
    incorrect: { tone: "red", label: "✕ Incorrect" },
  };

  return (
    <div style={{ minHeight: "100vh", background: COLORS.bg, fontFamily: "'IBM Plex Sans', sans-serif", display: "flex", flexDirection: "column" }}>
      <div style={{ background: COLORS.surface, borderBottom: `1px solid ${COLORS.line}`, padding: "10px 18px" }}>
        <div style={{ maxWidth: 680, margin: "0 auto", display: "flex", justifyContent: "space-between", alignItems: "center" }}>
          <div style={{ fontSize: 12.5, color: COLORS.inkSoft }}>🧑‍⚕️ <b style={{ color: COLORS.ink }}>{caseData.profil}</b> · {caseData.motif}</div>
          <button onClick={() => onFinish()} style={{ ...secondaryBtn, padding: "5px 10px", fontSize: 11.5 }}>Quitter</button>
        </div>
      </div>

      <div ref={scrollRef} style={{ flex: 1, overflowY: "auto", maxWidth: 680, width: "100%", margin: "0 auto", padding: "18px 18px 12px", display: "flex", flexDirection: "column", gap: 10 }}>
        {messages.map((m, i) => {
          if (m.role === "examen") {
            return (
              <div key={i} style={{ alignSelf: "center", background: COLORS.blueSoft, border: `1px solid ${COLORS.line}`, borderRadius: 10, padding: "8px 13px", fontSize: 12, color: COLORS.blueDeep, maxWidth: "90%" }}>
                🔬 {m.text}
              </div>
            );
          }
          const isPatient = m.role === "patient";
          return (
            <div
              key={i}
              style={{
                alignSelf: isPatient ? "flex-start" : "flex-end", maxWidth: "85%",
                padding: "10px 14px", borderRadius: 14, fontSize: 13.5, lineHeight: 1.55,
                background: isPatient ? COLORS.surface : COLORS.blue,
                border: isPatient ? `1px solid ${COLORS.line}` : "none",
                color: isPatient ? COLORS.ink : "white",
                borderBottomLeftRadius: isPatient ? 4 : 14,
                borderBottomRightRadius: isPatient ? 14 : 4,
              }}
            >
              {isPatient && <div style={{ fontSize: 10, fontWeight: 700, color: COLORS.inkSoft, marginBottom: 3 }}>PATIENT</div>}
              {m.text}
            </div>
          );
        })}
        {asking && <div style={{ alignSelf: "flex-start", fontSize: 12, color: COLORS.inkSoft, fontStyle: "italic" }}>Le patient réfléchit…</div>}
      </div>

      {phase === "chat" && (
        <div style={{ maxWidth: 680, width: "100%", margin: "0 auto", padding: "0 18px 18px" }}>
          {showExamMenu && (
            <div style={{ background: COLORS.surface, border: `1px solid ${COLORS.line}`, borderRadius: 12, padding: 10, marginBottom: 10, display: "flex", flexWrap: "wrap", gap: 6 }}>
              {caseData.examens.map((exam) => {
                const already = examResults.some((e) => e.nom === exam.nom);
                return (
                  <button
                    key={exam.nom}
                    onClick={() => requestExam(exam)}
                    disabled={already}
                    style={{
                      borderRadius: 999, padding: "6px 12px", fontSize: 12, cursor: already ? "default" : "pointer",
                      border: `1px solid ${already ? COLORS.line : COLORS.blue}`,
                      background: already ? "#F4F6F7" : COLORS.blueSoft,
                      color: already ? COLORS.inkSoft : COLORS.blueDeep, fontWeight: 600,
                    }}
                  >
                    {already ? "✓ " : ""}{exam.nom}
                  </button>
                );
              })}
            </div>
          )}
          <div style={{ display: "flex", gap: 8, marginBottom: 10 }}>
            <input
              value={input}
              onChange={(e) => setInput(e.target.value)}
              onKeyDown={(e) => { if (e.key === "Enter") askQuestion(); }}
              placeholder="Posez une question au patient…"
              style={{ ...inputStyle, fontFamily: "'IBM Plex Sans', sans-serif", flex: 1 }}
            />
            <button onClick={askQuestion} disabled={!input.trim() || asking} style={{ ...primaryBtn, opacity: !input.trim() || asking ? 0.5 : 1 }}>Envoyer</button>
          </div>
          <div style={{ display: "flex", gap: 8 }}>
            <button onClick={() => setShowExamMenu((s) => !s)} style={{ ...secondaryBtn, flex: 1, fontSize: 12.5 }}>🔬 Demander un examen</button>
            <button onClick={() => setPhase("answer")} style={{ ...primaryBtn, background: COLORS.green, flex: 1, fontSize: 12.5 }}>Poser mon diagnostic →</button>
          </div>
        </div>
      )}

      {phase === "answer" && (
        <div style={{ maxWidth: 680, width: "100%", margin: "0 auto", padding: "0 18px 18px" }}>
          <div style={{ background: COLORS.surface, border: `1px solid ${COLORS.line}`, borderRadius: 12, padding: 14, marginBottom: 10 }}>
            <div style={{ fontSize: 12, fontWeight: 700, color: COLORS.blueDeep, marginBottom: 6 }}>Votre diagnostic, la conduite à tenir et les soins infirmiers :</div>
            <textarea
              value={finalAnswer}
              onChange={(e) => setFinalAnswer(e.target.value)}
              rows={5}
              placeholder="Rédigez votre réponse complète…"
              style={{ ...inputStyle, fontFamily: "'IBM Plex Sans', sans-serif", resize: "vertical" }}
            />
          </div>
          <div style={{ display: "flex", gap: 8 }}>
            <button onClick={() => setPhase("chat")} style={{ ...secondaryBtn, flex: 1 }}>← Revenir à la discussion</button>
            <button onClick={submitFinal} disabled={!finalAnswer.trim() || grading} style={{ ...primaryBtn, background: COLORS.green, flex: 1, opacity: !finalAnswer.trim() || grading ? 0.5 : 1 }}>
              {grading ? "Évaluation…" : "Valider"}
            </button>
          </div>
        </div>
      )}

      {phase === "result" && result && (
        <div style={{ maxWidth: 680, width: "100%", margin: "0 auto", padding: "0 18px 24px" }}>
          <div style={{ background: COLORS.surface, border: `1px solid ${COLORS.line}`, borderRadius: 12, padding: 16 }}>
            {result.error ? (
              <div style={{ fontSize: 12.5, color: COLORS.red }}>La correction IA n'a pas pu être obtenue. Réessayez.</div>
            ) : (
              <>
                <Badge tone={verdictStyle[result.verdict].tone}>{verdictStyle[result.verdict].label}</Badge>
                <div style={{ fontSize: 13, color: COLORS.ink, lineHeight: 1.6, marginTop: 10 }}>{result.explication}</div>
                {result.verdict !== "correct" && (
                  <div style={{ marginTop: 10, paddingTop: 10, borderTop: `1px dashed ${COLORS.line}` }}>
                    <div style={{ fontSize: 10.5, fontWeight: 700, color: COLORS.blueDeep, letterSpacing: 0.4, marginBottom: 4 }}>RÉPONSE ATTENDUE</div>
                    <div style={{ fontSize: 13, color: COLORS.ink, lineHeight: 1.6 }}>{result.rappel}</div>
                  </div>
                )}
              </>
            )}
            <button onClick={() => onFinish()} style={{ ...primaryBtn, width: "100%", marginTop: 16 }}>Retour au tableau de bord</button>
          </div>
        </div>
      )}
    </div>
  );
}

function LessonScreen({ subjectId, chapterId, onBack, onStartTraining }) {
  const sections = useMemo(() => buildLessonSections(subjectId, chapterId), [subjectId, chapterId]);
  const title = chapterId === "all" ? "Toute la matière" : CH[chapterId];

  return (
    <div style={{ minHeight: "100vh", background: COLORS.bg, fontFamily: "'IBM Plex Sans', sans-serif" }}>
      <TopBar onLogout={onBack} />
      <div style={{ maxWidth: 760, margin: "0 auto", padding: "26px 18px 100px" }}>
        <button onClick={onBack} style={{ ...secondaryBtn, marginBottom: 18, padding: "6px 12px", fontSize: 12.5 }}>← Retour</button>
        <div style={{ marginBottom: 4 }}><Badge tone="blue">{SUBJ[subjectId] || "Matière"}</Badge></div>
        <h1 style={{ fontFamily: "'Space Grotesk', sans-serif", fontSize: 20, color: COLORS.ink, margin: "8px 0 4px" }}>{title}</h1>
        <p style={{ color: COLORS.inkSoft, fontSize: 13, marginBottom: 22 }}>
          Résumé des notions à maîtriser, tirées directement du cours. Une fois prêt(e), lancez l'entraînement sur ce chapitre.
        </p>

        {sections.length === 0 ? (
          <div style={{ background: COLORS.surface, border: `1px solid ${COLORS.line}`, borderRadius: 12, padding: 18, fontSize: 13, color: COLORS.inkSoft }}>
            Pas encore de résumé disponible pour ce chapitre.
          </div>
        ) : (
          <div style={{ display: "flex", flexDirection: "column", gap: 20 }}>
            {sections.map((s) => (
              <div key={s.chapterId}>
                {chapterId === "all" && (
                  <h2 style={{ fontFamily: "'Space Grotesk', sans-serif", fontSize: 15, color: COLORS.blueDeep, marginBottom: 10 }}>{s.chapterLabel}</h2>
                )}
                <div style={{ background: COLORS.surface, border: `1px solid ${COLORS.line}`, borderRadius: 14, padding: 18 }}>
                  <div style={{ fontSize: 11, fontWeight: 700, color: COLORS.green, letterSpacing: 0.4, marginBottom: 10 }}>NOTIONS À MAÎTRISER</div>
                  <ul style={{ margin: 0, paddingLeft: 18, display: "flex", flexDirection: "column", gap: 10 }}>
                    {s.facts.map((f, i) => (
                      <li key={i} style={{ fontSize: 13.5, color: COLORS.ink, lineHeight: 1.65 }}>
                        {f.explanation}
                        <div style={{ fontSize: 10.5, color: COLORS.inkSoft, marginTop: 2, fontFamily: "'IBM Plex Mono', monospace" }}>{f.reference}</div>
                      </li>
                    ))}
                  </ul>
                </div>
              </div>
            ))}
          </div>
        )}

        <button
          onClick={() => onStartTraining(chapterId)}
          style={{ ...primaryBtn, background: COLORS.green, width: "100%", marginTop: 24 }}
        >
          Commencer l'entraînement sur ce chapitre →
        </button>
      </div>
    </div>
  );
}

/* ---------------- Entraînement : session avec correction immédiate ---------------- */
function TrainingScreen({ session, onFinish }) {
  const flat = useMemo(() => flattenGradable(session.items), [session]);
  const [cursor, setCursor] = useState(0);
  const [selected, setSelected] = useState([]);
  const [checked, setChecked] = useState(false);
  const [tally, setTally] = useState({ correct: 0, attempted: 0 });

  const current = flat[cursor];
  const isLast = cursor === flat.length - 1;

  if (!current) {
    return (
      <div style={{ minHeight: "100vh", background: COLORS.bg, display: "flex", alignItems: "center", justifyContent: "center", padding: 20, fontFamily: "'IBM Plex Sans', sans-serif" }}>
        <div style={{ maxWidth: 420, background: COLORS.surface, border: `1px solid ${COLORS.line}`, borderRadius: 16, padding: 28, textAlign: "center" }}>
          <div style={{ fontSize: 13, color: COLORS.ink, marginBottom: 16 }}>Aucune question disponible pour ce choix pour le moment.</div>
          <button onClick={() => onFinish(null)} style={{ ...primaryBtn, width: "100%" }}>Retour au tableau de bord</button>
        </div>
      </div>
    );
  }

  const toggle = (optId) => {
    if (checked) return;
    if (current.type === "QCU") { setSelected([optId]); return; }
    setSelected((prev) => (prev.includes(optId) ? prev.filter((o) => o !== optId) : [...prev, optId]));
  };

  const verify = () => {
    if (selected.length === 0) return;
    const correctIds = current.options.filter((o) => o.correct).map((o) => o.id);
    const exact = selected.length === correctIds.length && selected.every((s) => correctIds.includes(s));
    setTally((t) => ({ correct: t.correct + (exact ? 1 : 0), attempted: t.attempted + 1 }));
    setChecked(true);
  };

  const next = () => {
    setSelected([]);
    setChecked(false);
    if (isLast) { onFinish(tally); return; }
    setCursor((c) => c + 1);
  };

  const correctIds = current.options.filter((o) => o.correct).map((o) => o.id);

  return (
    <div style={{ minHeight: "100vh", background: COLORS.bg, fontFamily: "'IBM Plex Sans', sans-serif" }}>
      <div style={{ background: COLORS.surface, borderBottom: `1px solid ${COLORS.line}`, padding: "10px 18px" }}>
        <div style={{ maxWidth: 720, margin: "0 auto", display: "flex", justifyContent: "space-between", alignItems: "center", fontSize: 12.5, color: COLORS.inkSoft }}>
          <span>Entraînement · Question <b style={{ color: COLORS.ink }}>{cursor + 1}</b> / {flat.length}</span>
          <span style={{ fontFamily: "'IBM Plex Mono', monospace", color: COLORS.green, fontWeight: 600 }}>{tally.correct}/{tally.attempted} correctes</span>
        </div>
        <div style={{ maxWidth: 720, margin: "8px auto 0", height: 4, background: COLORS.line, borderRadius: 999 }}>
          <div style={{ width: `${((cursor + 1) / flat.length) * 100}%`, height: 4, background: COLORS.green, borderRadius: 999, transition: "width .25s" }} />
        </div>
      </div>

      <div style={{ maxWidth: 720, margin: "0 auto", padding: "24px 18px 80px" }}>
        {current.caseVignette && (
          <div style={{ background: COLORS.blueSoft, border: `1px solid ${COLORS.line}`, borderRadius: 12, padding: 16, marginBottom: 16 }}>
            <div style={{ fontSize: 10.5, fontWeight: 700, color: COLORS.blueDeep, letterSpacing: 0.4, marginBottom: 6 }}>CAS CLINIQUE</div>
            <div style={{ fontSize: 13.5, color: COLORS.ink, lineHeight: 1.6 }}>{current.caseVignette}</div>
          </div>
        )}

        <div style={{ marginBottom: 14, display: "flex", gap: 8, flexWrap: "wrap" }}>
          <Badge tone="blue">{current.chapterLabel}</Badge>
          {current.type === "QCM" && <Badge tone="amber">Une ou plusieurs réponses exactes</Badge>}
        </div>

        <div style={{ background: COLORS.surface, border: `1px solid ${COLORS.line}`, borderRadius: 14, padding: 20 }}>
          <div style={{ fontSize: 15, color: COLORS.ink, lineHeight: 1.55, marginBottom: 16, fontWeight: 500 }}>{current.stem}</div>
          <div style={{ display: "flex", flexDirection: "column", gap: 9 }}>
            {current.options.map((opt, i) => {
              const isSel = selected.includes(opt.id);
              let border = COLORS.line, bg = "#FBFDFE", fg = COLORS.ink;
              if (checked) {
                if (opt.correct) { border = COLORS.green; bg = COLORS.greenSoft; fg = COLORS.green; }
                else if (isSel) { border = COLORS.red; bg = COLORS.redSoft; fg = COLORS.red; }
              } else if (isSel) {
                border = COLORS.blue; bg = COLORS.blueSoft;
              }
              return (
                <button
                  key={opt.id}
                  onClick={() => toggle(opt.id)}
                  disabled={checked}
                  style={{ textAlign: "left", display: "flex", gap: 10, alignItems: "flex-start", padding: "11px 13px", borderRadius: 10, cursor: checked ? "default" : "pointer", border: `1.5px solid ${border}`, background: bg }}
                >
                  <span style={{ minWidth: 22, height: 22, borderRadius: current.type === "QCU" ? 999 : 6, border: `1.5px solid ${fg}`, background: isSel || (checked && opt.correct) ? fg : "white", color: "white", fontSize: 11, fontWeight: 700, display: "flex", alignItems: "center", justifyContent: "center", flexShrink: 0, marginTop: 1 }}>
                    {checked ? (opt.correct ? "✓" : isSel ? "✕" : "") : isSel ? "✓" : letters(current.options.length)[i]}
                  </span>
                  <span style={{ fontSize: 13.5, color: fg, lineHeight: 1.5 }}>{opt.text}</span>
                </button>
              );
            })}
          </div>
        </div>

        {checked && (
          <div style={{ background: COLORS.surface, border: `1px solid ${COLORS.line}`, borderRadius: 12, padding: 16, marginTop: 14 }}>
            <div style={{ fontSize: 12.5, color: COLORS.inkSoft, lineHeight: 1.6 }}>
              <b style={{ color: COLORS.blueDeep }}>Explication : </b>{current.explanation}
              <div style={{ fontSize: 11, marginTop: 8, fontFamily: "'IBM Plex Mono', monospace", color: COLORS.inkSoft }}>Réf. cours : {current.reference}</div>
            </div>
          </div>
        )}

        <div style={{ display: "flex", justifyContent: "flex-end", marginTop: 18 }}>
          {!checked ? (
            <button onClick={verify} disabled={selected.length === 0} style={{ ...primaryBtn, opacity: selected.length === 0 ? 0.5 : 1 }}>
              Vérifier ma réponse
            </button>
          ) : (
            <button onClick={next} style={{ ...primaryBtn, background: COLORS.green }}>
              {isLast ? "Terminer la séance" : "Question suivante →"}
            </button>
          )}
        </div>

        <button onClick={() => onFinish(tally)} style={{ ...secondaryBtn, marginTop: 22, fontSize: 12, color: COLORS.inkSoft }}>
          Quitter l'entraînement
        </button>
      </div>
    </div>
  );
}

/* ---------------- Exam ---------------- */
const CASE_TIME_LIMIT = 30; // décompte fixe pour les cas cliniques, quel que soit le niveau

function ExamScreen({ exam, onSubmit, onAbort, onFraud }) {
  const flat = useMemo(() => flattenGradable(exam.items), [exam]);
  const levelCfg = LEVELS.find((l) => l.id === exam.levelId);
  const perQuestionLimit = levelCfg?.timePerQuestion || null;
  const isTimed = !!perQuestionLimit;
  const hasCases = useMemo(() => flat.some((q) => q.kind === "caseq"), [flat]);
  const lockNavigation = isTimed || hasCases;

  const [answers, setAnswers] = useState({});
  const [cursor, setCursor] = useState(0);
  const [startTime] = useState(Date.now());
  const [elapsed, setElapsed] = useState(0);
  const [qLimit, setQLimit] = useState(null);
  const [qTimeLeft, setQTimeLeft] = useState(0);
  const [toast, setToast] = useState(null);
  const [photosTaken, setPhotosTaken] = useState(0);

  const camVideoRef = useRef(null);
  const camStreamRef = useRef(null);
  const fraudFiredRef = useRef(false);

  useEffect(() => {
    const t = setInterval(() => setElapsed(Math.floor((Date.now() - startTime) / 1000)), 1000);
    return () => clearInterval(t);
  }, [startTime]);

  // surveillance : photo silencieuse périodique pendant toute l'épreuve
  useEffect(() => {
    let active = true;
    navigator.mediaDevices?.getUserMedia?.({ video: true, audio: false })
      .then((s) => {
        if (!active) { s.getTracks().forEach((t) => t.stop()); return; }
        camStreamRef.current = s;
        if (camVideoRef.current) {
          camVideoRef.current.srcObject = s;
          camVideoRef.current.play().catch(() => {});
        }
      })
      .catch(() => {});
    const snap = setInterval(() => setPhotosTaken((n) => n + 1), 45000);
    return () => {
      active = false;
      clearInterval(snap);
      if (camStreamRef.current) camStreamRef.current.getTracks().forEach((t) => t.stop());
    };
  }, []);

  // détection de tentative de fraude : changement d'onglet / mise en arrière-plan
  useEffect(() => {
    const triggerFraud = () => {
      if (fraudFiredRef.current) return;
      fraudFiredRef.current = true;
      const durationSec = Math.floor((Date.now() - startTime) / 1000);
      onFraud(durationSec);
    };
    const handleVisibility = () => { if (document.hidden) triggerFraud(); };
    document.addEventListener("visibilitychange", handleVisibility);
    return () => document.removeEventListener("visibilitychange", handleVisibility);
    // eslint-disable-next-line react-hooks/exhaustive-deps
  }, []);

  const current = flat[cursor];
  const answeredCount = Object.keys(answers).filter((k) => answers[k] && answers[k].length > 0).length;
  const allAnswered = answeredCount === flat.length;
  const isLast = cursor === flat.length - 1;

  const goNext = useCallback(() => {
    setCursor((c) => (c < flat.length - 1 ? c + 1 : c));
  }, [flat.length]);

  // décompte par question : 30s fixe pour les cas cliniques (tous niveaux), sinon
  // le décompte du niveau (Avancé/Concours) le cas échéant, sinon pas de limite
  useEffect(() => {
    const limit = current?.kind === "caseq" ? CASE_TIME_LIMIT : isTimed ? perQuestionLimit : null;
    setQLimit(limit);
    if (!limit) return;
    setQTimeLeft(limit);
    const tick = setInterval(() => {
      setQTimeLeft((prev) => {
        if (prev <= 1) {
          clearInterval(tick);
          // temps écoulé : la réponse déjà sélectionnée (ou l'absence de réponse)
          // est validée telle quelle, puis passage automatique à la question suivante
          setToast("Temps écoulé — votre réponse a été validée telle quelle.");
          setTimeout(() => setToast(null), 1800);
          setTimeout(() => setCursor((c) => (c < flat.length - 1 ? c + 1 : c)), 250);
          return 0;
        }
        return prev - 1;
      });
    }, 1000);
    return () => clearInterval(tick);
    // eslint-disable-next-line react-hooks/exhaustive-deps
  }, [cursor]);

  const toggle = (optId) => {
    setAnswers((prev) => {
      const prevSel = prev[current.id] || [];
      if (current.type === "QCU") {
        return { ...prev, [current.id]: [optId] };
      }
      const has = prevSel.includes(optId);
      const next = has ? prevSel.filter((o) => o !== optId) : [...prevSel, optId];
      return { ...prev, [current.id]: next };
    });
  };

  const canSubmit = lockNavigation ? true : allAnswered;

  const submit = () => {
    const durationSec = Math.floor((Date.now() - startTime) / 1000);
    if (camStreamRef.current) camStreamRef.current.getTracks().forEach((t) => t.stop());
    onSubmit(answers, durationSec);
  };

  const isQuestionTimed = !!qLimit;
  const timerTone = qTimeLeft <= 5 ? COLORS.red : qTimeLeft <= 10 ? COLORS.amber : COLORS.green;

  return (
    <div style={{ minHeight: "100vh", background: COLORS.bg, fontFamily: "'IBM Plex Sans', sans-serif" }}>
      <video ref={camVideoRef} muted playsInline style={{ display: "none" }} />
      {toast && (
        <div
          style={{
            position: "fixed", top: 14, left: "50%", transform: "translateX(-50%)", zIndex: 50,
            background: COLORS.blueDeep, color: "white", fontSize: 12.5, fontWeight: 600,
            padding: "9px 16px", borderRadius: 999, boxShadow: "0 4px 12px rgba(7,58,87,0.3)",
          }}
        >
          ⏱ {toast}
        </div>
      )}
      <div style={{ background: COLORS.surface, borderBottom: `1px solid ${COLORS.line}`, padding: "10px 18px" }}>
        <div style={{ maxWidth: 720, margin: "0 auto", display: "flex", justifyContent: "space-between", alignItems: "center" }}>
          <div style={{ fontSize: 12.5, color: COLORS.inkSoft, display: "flex", alignItems: "center", gap: 10 }}>
            <span>Question <b style={{ color: COLORS.ink }}>{cursor + 1}</b> / {flat.length} · {answeredCount}/{flat.length} répondues</span>
            <span style={{ fontSize: 10.5, color: COLORS.inkSoft, opacity: 0.75 }}>📷 Surveillance active{photosTaken > 0 ? ` · ${photosTaken}` : ""}</span>
          </div>
          <div style={{ display: "flex", alignItems: "center", gap: 12 }}>
            {isQuestionTimed && (
              <div
                style={{
                  display: "flex", alignItems: "center", gap: 6,
                  fontFamily: "'IBM Plex Mono', monospace", fontSize: 13, fontWeight: 700,
                  color: timerTone, background: qTimeLeft <= 5 ? COLORS.redSoft : "transparent",
                  padding: qTimeLeft <= 5 ? "3px 9px" : 0, borderRadius: 999,
                }}
              >
                <span style={{ width: 7, height: 7, borderRadius: 999, background: timerTone, display: "inline-block" }} />
                {qTimeLeft}s
              </div>
            )}
            <div style={{ fontFamily: "'IBM Plex Mono', monospace", fontSize: 13, color: COLORS.blueDeep, fontWeight: 600 }}>{fmtTime(elapsed)}</div>
          </div>
        </div>
        <div style={{ maxWidth: 720, margin: "8px auto 0", height: 4, background: COLORS.line, borderRadius: 999 }}>
          <div style={{ width: `${((cursor + 1) / flat.length) * 100}%`, height: 4, background: COLORS.blue, borderRadius: 999, transition: "width .25s" }} />
        </div>
        {isQuestionTimed && (
          <div style={{ maxWidth: 720, margin: "4px auto 0", height: 3, background: COLORS.line, borderRadius: 999, overflow: "hidden" }}>
            <div
              style={{
                width: `${(qTimeLeft / qLimit) * 100}%`, height: 3, background: timerTone,
                borderRadius: 999, transition: "width 1s linear",
              }}
            />
          </div>
        )}
      </div>

      <div style={{ maxWidth: 720, margin: "0 auto", padding: "24px 18px 120px" }}>
        {current.caseVignette && (
          <div style={{ background: COLORS.blueSoft, border: `1px solid ${COLORS.line}`, borderRadius: 12, padding: 16, marginBottom: 16 }}>
            <div style={{ fontSize: 10.5, fontWeight: 700, color: COLORS.blueDeep, letterSpacing: 0.4, marginBottom: 6 }}>CAS CLINIQUE {isQuestionTimed && current.kind === "caseq" ? "· 30s" : ""}</div>
            <div style={{ fontSize: 13.5, color: COLORS.ink, lineHeight: 1.6 }}>{current.caseVignette}</div>
          </div>
        )}

        {current.type === "QCM" && (
          <div style={{ background: COLORS.amberSoft, border: `1px solid ${COLORS.line}`, borderRadius: 10, padding: "9px 13px", fontSize: 12, color: COLORS.amber, marginBottom: 14 }}>
            Consigne : une ou plusieurs réponses sont exactes. Toute réponse fausse cochée entraîne une pénalité. Réfléchissez avant de répondre.
          </div>
        )}

        <div style={{ background: COLORS.surface, border: `1px solid ${COLORS.line}`, borderRadius: 14, padding: 20 }}>
          <div style={{ fontSize: 15, color: COLORS.ink, lineHeight: 1.55, marginBottom: 16, fontWeight: 500 }}>{current.stem}</div>
          <div style={{ display: "flex", flexDirection: "column", gap: 9 }}>
            {current.options.map((opt, i) => {
              const sel = (answers[current.id] || []).includes(opt.id);
              return (
                <button
                  key={opt.id}
                  onClick={() => toggle(opt.id)}
                  style={{
                    textAlign: "left", display: "flex", gap: 10, alignItems: "flex-start",
                    padding: "11px 13px", borderRadius: 10, cursor: "pointer",
                    border: sel ? `1.5px solid ${COLORS.blue}` : `1px solid ${COLORS.line}`,
                    background: sel ? COLORS.blueSoft : "#FBFDFE",
                  }}
                >
                  <span
                    style={{
                      minWidth: 22, height: 22, borderRadius: current.type === "QCU" ? 999 : 6,
                      border: `1.5px solid ${sel ? COLORS.blue : COLORS.line}`,
                      background: sel ? COLORS.blue : "white",
                      color: "white", fontSize: 11, fontWeight: 700,
                      display: "flex", alignItems: "center", justifyContent: "center", flexShrink: 0, marginTop: 1,
                    }}
                  >
                    {sel ? "✓" : letters(current.options.length)[i]}
                  </span>
                  <span style={{ fontSize: 13.5, color: COLORS.ink, lineHeight: 1.5 }}>{opt.text}</span>
                </button>
              );
            })}
          </div>
        </div>

        {lockNavigation && (
          <div style={{ fontSize: 11.5, color: COLORS.inkSoft, marginTop: 14, textAlign: "center" }}>
            {isTimed
              ? <>Épreuve chronométrée : {perQuestionLimit}s par question ({hasCases ? "30s pour les cas cliniques" : "hors cas cliniques"}) · retour en arrière désactivé</>
              : <>Cas clinique chronométré : 30s par question · retour en arrière désactivé pour cette épreuve</>}
          </div>
        )}

        <div style={{ display: "flex", justifyContent: lockNavigation ? "flex-end" : "space-between", marginTop: 18 }}>
          {!lockNavigation && (
            <button disabled={cursor === 0} onClick={() => setCursor((c) => c - 1)} style={{ ...secondaryBtn, opacity: cursor === 0 ? 0.4 : 1 }}>
              ← Précédent
            </button>
          )}
          {!isLast ? (
            <button onClick={goNext} style={primaryBtn}>Suivant →</button>
          ) : (
            <button onClick={submit} disabled={!canSubmit} style={{ ...primaryBtn, background: COLORS.green, opacity: canSubmit ? 1 : 0.45 }}>
              Soumettre
            </button>
          )}
        </div>
        {isLast && !lockNavigation && !allAnswered && (
          <div style={{ textAlign: "right", fontSize: 11.5, color: COLORS.red, marginTop: 8 }}>
            Répondez aux {flat.length - answeredCount} question(s) restante(s) pour soumettre.
          </div>
        )}
        {isLast && lockNavigation && !allAnswered && (
          <div style={{ textAlign: "right", fontSize: 11.5, color: COLORS.amber, marginTop: 8 }}>
            {flat.length - answeredCount} question(s) sans réponse — elles seront comptées comme telles.
          </div>
        )}

        {!lockNavigation && (
          <div style={{ display: "flex", flexWrap: "wrap", gap: 6, marginTop: 26 }}>
            {flat.map((q, i) => {
              const done = (answers[q.id] || []).length > 0;
              return (
                <button
                  key={q.id}
                  onClick={() => setCursor(i)}
                  title={`Question ${i + 1}`}
                  style={{
                    width: 28, height: 28, borderRadius: 7, fontSize: 11, fontFamily: "'IBM Plex Mono', monospace",
                    border: i === cursor ? `1.5px solid ${COLORS.blue}` : `1px solid ${COLORS.line}`,
                    background: done ? COLORS.greenSoft : "white",
                    color: done ? COLORS.green : COLORS.inkSoft, cursor: "pointer",
                  }}
                >
                  {i + 1}
                </button>
              );
            })}
          </div>
        )}

        <button onClick={onAbort} style={{ ...secondaryBtn, marginTop: 22, fontSize: 12, color: COLORS.red }}>
          Abandonner l'examen
        </button>
      </div>
    </div>
  );
}

/* ---------------- Results ---------------- */
function ResultsScreen({ result, levelId, durationSec, onBackToDashboard }) {
  const { note20, obtained, maxTotal, percent, bonnes, mauvaises, oubliees, details } = result;
  return (
    <div style={{ minHeight: "100vh", background: COLORS.bg, fontFamily: "'IBM Plex Sans', sans-serif" }}>
      <TopBar onLogout={onBackToDashboard} />
      <div style={{ maxWidth: 760, margin: "0 auto", padding: "26px 18px 70px" }}>
        <div style={{ background: COLORS.blueDeep, borderRadius: 16, padding: 24, color: "white", marginBottom: 20 }}>
          <TraceDivider color="#8FC4E0" />
          <div style={{ display: "flex", justifyContent: "space-between", alignItems: "flex-end", marginTop: 10, flexWrap: "wrap", gap: 16 }}>
            <div>
              <div style={{ fontSize: 11, opacity: 0.75, letterSpacing: 0.5 }}>BULLETIN DE RÉSULTATS · {LEVELS.find((l) => l.id === levelId)?.label}</div>
              <div style={{ fontFamily: "'IBM Plex Mono', monospace", fontSize: 44, fontWeight: 600, marginTop: 4 }}>
                {note20.toFixed(1)}<span style={{ fontSize: 20, opacity: 0.7 }}>/20</span>
              </div>
            </div>
            <div style={{ display: "flex", gap: 18, fontSize: 12.5 }}>
              <div><div style={{ opacity: 0.7 }}>Score</div><div style={{ fontFamily: "'IBM Plex Mono', monospace" }}>{obtained}/{maxTotal}</div></div>
              <div><div style={{ opacity: 0.7 }}>%</div><div style={{ fontFamily: "'IBM Plex Mono', monospace" }}>{percent.toFixed(0)}%</div></div>
              <div><div style={{ opacity: 0.7 }}>Temps</div><div style={{ fontFamily: "'IBM Plex Mono', monospace" }}>{fmtTime(durationSec)}</div></div>
            </div>
          </div>
        </div>

        <div style={{ display: "grid", gridTemplateColumns: "repeat(3, 1fr)", gap: 10, marginBottom: 26 }}>
          <StatCard label="Bonnes réponses" value={bonnes} tone="green" />
          <StatCard label="Mauvaises réponses" value={mauvaises} />
          <StatCard label="Sans réponse" value={oubliees} />
        </div>

        <h2 style={{ fontFamily: "'Space Grotesk', sans-serif", fontSize: 16, color: COLORS.ink, marginBottom: 12 }}>Correction détaillée</h2>
        <div style={{ display: "flex", flexDirection: "column", gap: 12 }}>
          {details.map((q, i) => (
            <div key={q.id} style={{ background: COLORS.surface, border: `1px solid ${COLORS.line}`, borderRadius: 12, padding: 16 }}>
              <div style={{ display: "flex", justifyContent: "space-between", gap: 10, marginBottom: 8, flexWrap: "wrap" }}>
                <Badge tone="blue">{q.chapterLabel}</Badge>
                <Badge tone={q.status === "bonne" ? "green" : q.status === "oubliee" ? "amber" : "red"}>
                  {q.status === "bonne" ? "Correct" : q.status === "oubliee" ? "Sans réponse" : "Incorrect"} · {q.points}/{q.max} pt
                </Badge>
              </div>
              {q.caseVignette && (
                <div style={{ fontSize: 11.5, color: COLORS.inkSoft, background: COLORS.blueSoft, borderRadius: 8, padding: 10, marginBottom: 10 }}>
                  {q.caseVignette}
                </div>
              )}
              <div style={{ fontSize: 13.5, color: COLORS.ink, marginBottom: 10, fontWeight: 500 }}>{i + 1}. {q.stem}</div>
              <div style={{ display: "flex", flexDirection: "column", gap: 5, marginBottom: 10 }}>
                {q.options.map((opt) => {
                  const wasSelected = q.selected.includes(opt.id);
                  const isCorrect = opt.correct;
                  let bg = "#FBFDFE", border = COLORS.line, fg = COLORS.ink;
                  if (isCorrect) { bg = COLORS.greenSoft; border = COLORS.green; fg = COLORS.green; }
                  if (wasSelected && !isCorrect) { bg = COLORS.redSoft; border = COLORS.red; fg = COLORS.red; }
                  return (
                    <div key={opt.id} style={{ fontSize: 12.5, padding: "7px 10px", borderRadius: 8, border: `1px solid ${border}`, background: bg, color: fg, display: "flex", justifyContent: "space-between" }}>
                      <span>{opt.text}</span>
                      <span style={{ fontSize: 11, fontWeight: 600 }}>
                        {wasSelected ? "Votre choix" : ""}{wasSelected && isCorrect ? " ✓" : ""}{wasSelected && !isCorrect ? " ✕" : ""}
                        {!wasSelected && isCorrect ? "Réponse attendue ✓" : ""}
                      </span>
                    </div>
                  );
                })}
              </div>
              <div style={{ fontSize: 12.5, color: COLORS.inkSoft, lineHeight: 1.6, borderTop: `1px dashed ${COLORS.line}`, paddingTop: 10 }}>
                <b style={{ color: COLORS.blueDeep }}>Explication : </b>{q.explanation}
                <div style={{ fontSize: 11, marginTop: 6, fontFamily: "'IBM Plex Mono', monospace", color: COLORS.inkSoft }}>
                  Réf. cours : {q.reference}
                </div>
              </div>
            </div>
          ))}
        </div>

        <button onClick={onBackToDashboard} style={{ ...primaryBtn, width: "100%", marginTop: 24 }}>
          Retour au tableau de bord
        </button>
      </div>
    </div>
  );
}

/* ================= APP ================= */
export default function App() {
  useGoogleFonts();
  const [screen, setScreen] = useState("intro"); // intro | login | dashboard | matieres | setup | proctor | exam | results | fraud | admin | trainingSetup | training
  const [role, setRole] = useState(null); // "admin" | "student"
  const [history, setHistory] = useState([]);
  const [exam, setExam] = useState(null);
  const [trainingSession, setTrainingSession] = useState(null);
  const [flowMode, setFlowMode] = useState("exam"); // "exam" | "training"
  const [pendingSubject, setPendingSubject] = useState(null);
  const [pendingChapter, setPendingChapter] = useState(null);
  const [pendingCase, setPendingCase] = useState(null);
  const [pendingLevel, setPendingLevel] = useState(null);
  const [lastResult, setLastResult] = useState(null);
  const [loading, setLoading] = useState(true);
  const [student, setStudent] = useState(null);

  useEffect(() => {
    try {
      if (window.localStorage.getItem(INTRO_SEEN_KEY)) setScreen("login");
    } catch {}
  }, []);

  useEffect(() => {
    if (screen === "dashboard" && student?.matricule) {
      loadHistory(student.matricule).then((h) => {
        setHistory(h);
        setLoading(false);
      });
    }
  }, [screen, student]);

  const handleLogin = (loggedRole, studentRecord) => {
    setRole(loggedRole);
    if (loggedRole === "admin") {
      setScreen("admin");
    } else {
      setStudent(studentRecord);
      touchStudentLastSeen(studentRecord.matricule);
      setScreen("dashboard");
    }
  };
  const handleLogout = () => {
    setScreen("login"); setExam(null); setTrainingSession(null);
    setLastResult(null); setStudent(null); setRole(null);
  };
  const handleStart = () => { setFlowMode("exam"); setScreen("matieres"); };
  const handleTrain = () => { setFlowMode("training"); setScreen("matieres"); };
  const handleLearn = () => { setFlowMode("lesson"); setScreen("matieres"); };
  const handleDiagnostic = () => setScreen("diagnostic");
  const handleDiagnosticInfirmier = () => setScreen("diagnosticInfirmierSetup");
  const handleLaunchDI = (levelId) => { setPendingLevel(levelId); setScreen("diagnosticInfirmier"); };
  const handleVirtualPatient = () => setScreen("virtualPatientSetup");
  const handleLaunchVP = (caseId) => { setPendingCase(caseId); setScreen("virtualPatient"); };
  const handleSelectSubject = (subjectId) => {
    setPendingSubject(subjectId);
    if (flowMode === "training") setScreen("trainingSetup");
    else if (flowMode === "lesson") setScreen("lessonSetup");
    else setScreen("setup");
  };
  const handleLaunch = (levelId) => {
    setPendingLevel(levelId);
    setScreen("proctor");
  };
  const handleProctorReady = async () => {
    const seen = await loadSeen(student.matricule);
    const newExam = generateExam(pendingSubject, pendingLevel, seen);
    saveSeen(student.matricule, updateSeen(seen, newExam)); // fire-and-forget : mémorise ce qui vient d'être vu
    setExam(newExam);
    setScreen("exam");
  };
  const handleLaunchTraining = (chapterId) => {
    setTrainingSession(generateTraining(pendingSubject, chapterId));
    setScreen("training");
  };
  const handleLaunchLesson = (chapterId) => {
    setPendingChapter(chapterId);
    setScreen("lesson");
  };
  const handleTrainingFinish = () => {
    setTrainingSession(null);
    setScreen("dashboard");
  };
  const handleAbort = () => setScreen("dashboard");

  const handleMarkPending = async (planId) => {
    const updated = await markPaymentPending(student.matricule, planId);
    if (updated) setStudent(updated);
  };

  const handleSubmit = async (answers, durationSec) => {
    const result = scoreExam(exam.items, answers);
    const entry = {
      id: `res-${Date.now()}`,
      date: new Date().toISOString(),
      subjectId: exam.subjectId,
      levelId: exam.levelId,
      note20: result.note20,
      obtained: result.obtained,
      maxTotal: result.maxTotal,
      percent: result.percent,
      bonnes: result.bonnes,
      mauvaises: result.mauvaises,
      oubliees: result.oubliees,
      durationSec,
      chapterStats: result.chapterStats,
    };
    const newHistory = [...history, entry];
    setHistory(newHistory);
    await saveHistory(student.matricule, newHistory);
    if (student?.matricule) incrementStudentExamCount(student.matricule);
    setLastResult({ result, durationSec, levelId: exam.levelId });
    setScreen("results");
  };

  const handleFraud = async (durationSec) => {
    const entry = {
      id: `res-${Date.now()}`,
      date: new Date().toISOString(),
      subjectId: exam?.subjectId,
      levelId: exam?.levelId,
      note20: 0,
      obtained: 0,
      maxTotal: 0,
      percent: 0,
      bonnes: 0,
      mauvaises: 0,
      oubliees: 0,
      durationSec,
      chapterStats: {},
      aborted: true,
      reason: "fraude",
    };
    const newHistory = [...history, entry];
    setHistory(newHistory);
    await saveHistory(student.matricule, newHistory);
    if (student?.matricule) incrementStudentExamCount(student.matricule);
    setExam(null);
    setScreen("fraud");
  };

  if (screen === "intro") return <IntroScreen onContinue={() => setScreen("login")} />;

  if (screen === "login") return <LoginScreen onLogin={handleLogin} />;

  if (screen === "admin") return <AdminScreen onBack={handleLogout} />;

  if (screen === "dashboard") {
    if (loading) return <LoadingScreen />;
    return <Dashboard history={history} onStart={handleStart} onTrain={handleTrain} onLearn={handleLearn} onDiagnostic={handleDiagnostic} onDiagnosticInfirmier={handleDiagnosticInfirmier} onVirtualPatient={handleVirtualPatient} onLogout={handleLogout} student={student} onMarkPending={handleMarkPending} />;
  }

  if (screen === "matieres") return <MatieresScreen onBack={handleAbort} onSelect={handleSelectSubject} />;

  if (screen === "setup") return <SetupScreen subjectId={pendingSubject} onBack={() => setScreen("matieres")} onLaunch={handleLaunch} />;

  if (screen === "trainingSetup") return <TrainingSetupScreen subjectId={pendingSubject} onBack={() => setScreen("matieres")} onLaunch={handleLaunchTraining} />;

  if (screen === "lessonSetup") return <TrainingSetupScreen subjectId={pendingSubject} onBack={() => setScreen("matieres")} onLaunch={handleLaunchLesson} mode="lesson" />;

  if (screen === "lesson") return <LessonScreen subjectId={pendingSubject} chapterId={pendingChapter} onBack={() => setScreen("lessonSetup")} onStartTraining={handleLaunchTraining} />;

  if (screen === "diagnostic") return <DiagnosticScreen student={student} onBack={handleAbort} />;

  if (screen === "diagnosticInfirmierSetup") return <DiagnosticInfirmierSetupScreen onBack={handleAbort} onLaunch={handleLaunchDI} />;

  if (screen === "diagnosticInfirmier") return <DiagnosticInfirmierScreen levelId={pendingLevel} onFinish={handleAbort} />;

  if (screen === "virtualPatientSetup") return <VirtualPatientSetupScreen onBack={handleAbort} onLaunch={handleLaunchVP} />;

  if (screen === "virtualPatient") return <VirtualPatientScreen caseId={pendingCase} onFinish={handleAbort} />;

  if (screen === "training" && trainingSession) return <TrainingScreen session={trainingSession} onFinish={handleTrainingFinish} />;

  if (screen === "proctor") return <ProctorCheckScreen onReady={handleProctorReady} />;

  if (screen === "exam" && exam) return <ExamScreen exam={exam} onSubmit={handleSubmit} onAbort={handleAbort} onFraud={handleFraud} />;

  if (screen === "fraud") return <FraudScreen onBack={handleAbort} />;

  if (screen === "results" && lastResult) {
    return (
      <ResultsScreen
        result={lastResult.result}
        levelId={lastResult.levelId}
        durationSec={lastResult.durationSec}
        onBackToDashboard={() => setScreen("dashboard")}
      />
    );
  }

  return <LoadingScreen />;
}

function LoadingScreen() {
  return (
    <div style={{ minHeight: "100vh", background: COLORS.bg, display: "flex", alignItems: "center", justifyContent: "center", fontFamily: "'IBM Plex Sans', sans-serif", color: COLORS.inkSoft }}>
      Chargement…
    </div>
  );
}
